# Module providing geometric shape classes and interfaces
interface IShape:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

interface IDrawable:
    @abstract
    def draw(self) -> str: ...

class Rectangle(IShape, IDrawable):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Rectangle({self.width:.1f}x{self.height:.1f})"

class Circle(IShape, IDrawable):
    radius: float
    PI: float = 3.14159

    def __init__(self, radius: float):
        self.radius = radius

    @override
    def area(self) -> float:
        return self.PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * self.PI * self.radius

    @override
    def draw(self) -> str:
        return f"Circle(r={self.radius:.1f})"

class Square(Rectangle):
    def __init__(self, side: float):
        super().__init__(side, side)

    @override
    def draw(self) -> str:
        return f"Square(s={self.width:.1f})"

