# Module providing utility functions for shape calculations
from shapes import Rectangle, Circle, IShape

def calculate_total_area(shapes: list[IShape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def calculate_total_perimeter(shapes: list[IShape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.perimeter()
    return total

def create_rectangles(count: int) -> list[Rectangle]:
    result: list[Rectangle] = []
    i: int = 0
    while i < count:
        r: Rectangle = Rectangle(float(i + 1), float(i + 2))
        result.append(r)
        i += 1
    return result

def scale_factor(factor: float) -> float:
    return factor * 2.0
